UPDATE stocks
SET is_kept = #{kept}
WHERE external_id = #{externalId}
  AND status = 'IN_STOCK'
  AND item_id IN (
      SELECT id
      FROM items
      WHERE user_id = #{userId}
  )

UPDATE stocks
SET status = #{status},
    memo   = #{memo}
WHERE external_id = #{externalId}
  AND status = 'IN_STOCK'
  AND item_id IN (
      SELECT id
      FROM items
      WHERE user_id = #{userId}
  )

UPDATE stocks
SET status = #{status}
WHERE id = #{id}
  AND status = 'IN_STOCK'

