WHERE i.user_id = #{userId}
  AND s.status = 'IN_STOCK'

  AND i.external_id = #{itemExternalId}


  AND sp.external_id = #{spaceExternalId}


  AND sh.external_id = #{shelfExternalId}


  AND b.external_id = #{boxExternalId}


  AND (


            i.name LIKE CONCAT('%', #{keyword}, '%')


            s.serial_number LIKE CONCAT('%', #{keyword}, '%')


            COALESCE(il.lot_number, s.lot_number) LIKE CONCAT('%', #{keyword}, '%')


            s.memo LIKE CONCAT('%', #{keyword}, '%')


            i.name LIKE CONCAT('%', #{keyword}, '%')
            OR s.serial_number LIKE CONCAT('%', #{keyword}, '%')
            OR COALESCE(il.lot_number, s.lot_number) LIKE CONCAT('%', #{keyword}, '%')
            OR s.memo LIKE CONCAT('%', #{keyword}, '%')


  )

ORDER BY


        s.created_at ASC, s.id ASC


        i.name ASC, sp.name ASC, sh.name ASC, b.name ASC, s.created_at DESC


        s.created_at DESC, s.id DESC


LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM stocks s JOIN items i ON s.item_id = i.id JOIN spaces sp ON s.space_id = sp.id LEFT JOIN shelves sh ON s.shelf_id = sh.id LEFT JOIN boxes b ON s.box_id = b.id LEFT JOIN item_lots il ON s.lot_id = il.id WHERE i.user_id = #{userId} AND s.status = 'IN_STOCK'
AND i.external_id = #{itemExternalId}
AND sp.external_id = #{spaceExternalId}
AND sh.external_id = #{shelfExternalId}
AND b.external_id = #{boxExternalId}
AND (
i.name LIKE CONCAT('%', #{keyword}, '%')
s.serial_number LIKE CONCAT('%', #{keyword}, '%')
COALESCE(il.lot_number, s.lot_number) LIKE CONCAT('%', #{keyword}, '%')
s.memo LIKE CONCAT('%', #{keyword}, '%')
i.name LIKE CONCAT('%', #{keyword}, '%') OR s.serial_number LIKE CONCAT('%', #{keyword}, '%') OR COALESCE(il.lot_number, s.lot_number) LIKE CONCAT('%', #{keyword}, '%') OR s.memo LIKE CONCAT('%', #{keyword}, '%')
)

